def most_primes_group(data: dict) -> str:
    def count_primes(nums):
        c = 0
        for x in nums:
            if x < 2:
                continue
            is_p = True
            d = 2
            while d * d <= x:
                if x % d == 0:
                    is_p = False
                    break
                d += 1
            if is_p:
                c += 1
        return c
    best = None
    best_count = -1
    for group in sorted(data):
        c = count_primes(data[group])
        if c > best_count:
            best_count = c
            best = group
    return best
